public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        int maxTime = logs[0][1];
        int bestId = logs[0][0];
        int prevEnd = logs[0][1];
        for (size_t i = 1; i < logs.size(); ++i) {
            int duration = logs[i][1] - prevEnd;
            if (duration > maxTime) {
                maxTime = duration;
                bestId = logs[i][0];
            } else if (duration == maxTime) {
                if (logs[i][0] < bestId) bestId = logs[i][0];
            }
            prevEnd = logs[i][1];
        }
        return bestId;
    }
};
